import{_ as l}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as e}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as o,o as r,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"CloudFlare API Token 配置","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Safety/cloudflare-api-token.md","filePath":"cn/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"cn/Safety/cloudflare-api-token.md"};function p(n,a,h,u,s,c){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="cloudflare-api-token-配置" tabindex="-1">CloudFlare API Token 配置 <a class="header-anchor" href="#cloudflare-api-token-配置" aria-label="Permalink to &quot;CloudFlare API Token 配置&quot;">​</a></h1><p>CloudFlare API Token 用于让系统在文件发生变化时，主动清理 Cloudflare CDN 缓存。</p><p><img src="'+l+'" alt="CloudFlare API Token 配置" loading="lazy"></p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>进入后台后，打开：</p><p>系统配置 → 安全设置 → CloudFlare API Token</p><p>页面里需要填写三项：</p><ul><li>区域 ID</li><li>账户邮箱</li><li>API Key</li></ul><h2 id="这个配置有什么用" tabindex="-1">这个配置有什么用 <a class="header-anchor" href="#这个配置有什么用" aria-label="Permalink to &quot;这个配置有什么用&quot;">​</a></h2><p>Cloudflare 会缓存公开图片。</p><p>缓存可以让图片访问更快，但也会带来一个问题：当你删除、屏蔽、替换或移动图片后，外部访问可能还会短时间看到旧缓存。</p><p>配置 CloudFlare API Token 后，系统在相关操作完成时，会请求 Cloudflare 清理对应缓存。</p><p>适合这些场景：</p><ul><li>删除图片后，希望公开链接尽快失效。</li><li>屏蔽图片后，希望外部访问尽快不再看到原图。</li><li>覆盖同名图片后，希望用户尽快看到新图。</li><li>移动或重命名文件后，希望旧路径缓存尽快更新。</li><li>调整公开访问规则后，希望公开图床和随机图相关缓存尽快刷新。</li></ul><h2 id="不配置会怎样" tabindex="-1">不配置会怎样 <a class="header-anchor" href="#不配置会怎样" aria-label="Permalink to &quot;不配置会怎样&quot;">​</a></h2><p>不配置也可以正常使用图床。</p><p>只是 Cloudflare CDN 缓存不会被系统主动清理，外部用户可能会在缓存过期前继续看到旧内容。</p><p>这种情况通常会随着 Cloudflare 缓存自然过期而恢复，但不会立刻生效。</p><h2 id="区域-id-怎么填写" tabindex="-1">区域 ID 怎么填写 <a class="header-anchor" href="#区域-id-怎么填写" aria-label="Permalink to &quot;区域 ID 怎么填写&quot;">​</a></h2><p>区域 ID 是 Cloudflare 里当前站点的 Zone ID。</p><p>获取方式：</p><ol><li>登录 Cloudflare 控制台。</li><li>进入你的图床域名所在站点。</li><li>在站点概览页面找到 Zone ID。</li><li>复制后填入“区域 ID”。</li></ol><p>注意：这里填的是当前域名所在站点的 Zone ID，不是账号 ID。</p><h2 id="账户邮箱怎么填写" tabindex="-1">账户邮箱怎么填写 <a class="header-anchor" href="#账户邮箱怎么填写" aria-label="Permalink to &quot;账户邮箱怎么填写&quot;">​</a></h2><p>账户邮箱填写你的 Cloudflare 登录邮箱。</p><p>这个邮箱需要和下面的 API Key 配套使用。</p><h2 id="api-key-怎么填写" tabindex="-1">API Key 怎么填写 <a class="header-anchor" href="#api-key-怎么填写" aria-label="Permalink to &quot;API Key 怎么填写&quot;">​</a></h2><p>这里填写 Cloudflare 的 Global API Key。</p><p>获取方式：</p><ol><li>登录 Cloudflare 控制台。</li><li>进入个人资料。</li><li>打开 API Tokens 页面。</li><li>找到 Global API Key。</li><li>查看并复制。</li><li>粘贴到后台的 API Key 输入框。</li></ol><p><img src="'+e+'" alt="查看全局令牌" loading="lazy"></p><h2 id="保存后什么时候生效" tabindex="-1">保存后什么时候生效 <a class="header-anchor" href="#保存后什么时候生效" aria-label="Permalink to &quot;保存后什么时候生效&quot;">​</a></h2><p>填写完成后，点击页面右下角保存。</p><p>保存成功后，后续文件变更会自动尝试清理 Cloudflare 缓存。</p><p>已经发生过的旧操作不会自动补清。如果你之前删除或替换过文件，但当时没有配置这个信息，可能需要等 Cloudflare 缓存自然过期，或者到 Cloudflare 控制台手动清理缓存。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="一定要配置吗" tabindex="-1">一定要配置吗？ <a class="header-anchor" href="#一定要配置吗" aria-label="Permalink to &quot;一定要配置吗？&quot;">​</a></h3><p>不是必须。</p><p>如果你的域名没有接入 Cloudflare，或者你不在意 CDN 缓存延迟，可以不填。</p><h3 id="填错会影响上传吗" tabindex="-1">填错会影响上传吗？ <a class="header-anchor" href="#填错会影响上传吗" aria-label="Permalink to &quot;填错会影响上传吗？&quot;">​</a></h3><p>一般不会影响正常上传和访问。</p><p>填错后，系统只是无法成功请求 Cloudflare 清理缓存，旧缓存可能继续存在一段时间。</p><h3 id="为什么删除图片后外面还能打开" tabindex="-1">为什么删除图片后外面还能打开？ <a class="header-anchor" href="#为什么删除图片后外面还能打开" aria-label="Permalink to &quot;为什么删除图片后外面还能打开？&quot;">​</a></h3><p>最常见原因是 Cloudflare CDN 还缓存着旧文件。</p><p>配置正确的 CloudFlare API Token 后，系统会在删除时主动清理对应 URL 缓存。</p><h3 id="为什么替换同名图片后还是旧图" tabindex="-1">为什么替换同名图片后还是旧图？ <a class="header-anchor" href="#为什么替换同名图片后还是旧图" aria-label="Permalink to &quot;为什么替换同名图片后还是旧图？&quot;">​</a></h3><p>这也是 CDN 缓存导致的常见现象。</p><p>配置后，系统会在覆盖同名文件时尝试清理旧 URL 缓存，让新图更快生效。</p>',48)])])}const m=o(d,[["render",p]]);export{C as __pageData,m as default};
